mapper.select:
SELECT * FROM FUND_SUBJECT
WHERE `上级科目编码` = #{parentSubjectCode}
ORDER BY `科目编码` ASC

WITH RECURSIVE child_subjects AS (
    SELECT `科目编号`
    FROM FUND_SUBJECT
    WHERE `科目编码` = #{parentSubjectCode}
    UNION ALL
    SELECT fs.`科目编号`
    FROM FUND_SUBJECT fs
    INNER JOIN child_subjects cs ON fs.`上级科目编码` = cs.`科目编码`
)
SELECT `科目编号` FROM child_subjects WHERE `科目编码` != #{parentSubjectCode}
